import{_ as t,c as i,o,a5 as r,j as e}from"./chunks/framework.Dtwt352Q.js";const f=JSON.parse('{"title":"v1.1.54: Skill URL Discovery, More Stable ACP File Writing, Clearer Model Errors","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.54.md","filePath":"en/changelog/v1.1.54.md","lastUpdated":1772014034000}'),l={name:"en/changelog/v1.1.54.md"};function s(n,a,d,h,c,u){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="v1-1-54-skill-url-discovery-more-stable-acp-file-writing-clearer-model-errors" tabindex="-1">v1.1.54: Skill URL Discovery, More Stable ACP File Writing, Clearer Model Errors <a class="header-anchor" href="#v1-1-54-skill-url-discovery-more-stable-acp-file-writing-clearer-model-errors" aria-label="Permalink to “v1.1.54: Skill URL Discovery, More Stable ACP File Writing, Clearer Model Errors”">​</a></h1><p><strong>Release Date</strong>: February 11, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update completes the &quot;most common pitfalls in major versions&quot;: Skills can be auto-discovered via URL, ACP file writing automatically creates new files, model selection errors provide clear events and error types, and desktop/TUI fixed a batch of high-frequency issues.</p><hr><h2 id="new-feature-skill-auto-discovery-via-url" tabindex="-1">New Feature: Skill Auto-Discovery via URL <a class="header-anchor" href="#new-feature-skill-auto-discovery-via-url" aria-label="Permalink to “New Feature: Skill Auto-Discovery via URL”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>OpenCode added Skill URL discovery capability based on well-known RFC, making subsequent Skill integration via URL smoother.</p><h3 id="what-s-the-use-for-you" tabindex="-1">What&#39;s the Use for You? <a class="header-anchor" href="#what-s-the-use-for-you" aria-label="Permalink to “What&#39;s the Use for You?”">​</a></h3><p>Previously you needed to manually find Skill entry points; now you can go through the discovery process directly from standard URLs, especially suitable for teams to uniformly distribute Skills.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/03b-skills-advanced.html">Skills Advanced</a></p><p>👉 <strong>Official Docs</strong>: <a href="https://opencode.ai/docs/agents" target="_blank" rel="noreferrer">Agents</a></p><p><strong>Quick Experience</strong>:</p><ol><li>First confirm your Skill source address is publicly accessible.</li><li>Configure and trigger loading according to existing Skill process in your project.</li><li>Observe whether the corresponding Skill is auto-discovered and loaded via URL.</li></ol><hr><h2 id="new-feature-acp-auto-creates-non-existent-files-when-writing" tabindex="-1">New Feature: ACP Auto-Creates Non-Existent Files When Writing <a class="header-anchor" href="#new-feature-acp-auto-creates-non-existent-files-when-writing" aria-label="Permalink to “New Feature: ACP Auto-Creates Non-Existent Files When Writing”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>When writing files via ACP channel, if the target file doesn&#39;t exist, OpenCode now automatically creates the file before writing.</p><h3 id="what-s-the-use-for-you-1" tabindex="-1">What&#39;s the Use for You? <a class="header-anchor" href="#what-s-the-use-for-you-1" aria-label="Permalink to “What&#39;s the Use for You?”">​</a></h3><p>When you execute write operations in IDE + ACP scenarios, it no longer fails directly because &quot;file hasn&#39;t been created yet&quot;, making automation scripts more stable.</p><h3 id="how-to-use-1" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to Use?”">​</a></h3><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/08b-acp.html">ACP Protocol</a></p><p>👉 <strong>Official Docs</strong>: <a href="https://opencode.ai/docs/acp" target="_blank" rel="noreferrer">ACP Support</a></p><p><strong>Quick Experience</strong>:</p><ol><li>Start ACP according to tutorial (<code>opencode acp</code>).</li><li>Let Agent write to a non-existent path.</li><li>Confirm file is created and written successfully.</li></ol><hr><h2 id="new-feature-enhanced-model-selection-error-events-and-error-types" tabindex="-1">New Feature: Enhanced Model Selection Error Events and Error Types <a class="header-anchor" href="#new-feature-enhanced-model-selection-error-events-and-error-types" aria-label="Permalink to “New Feature: Enhanced Model Selection Error Events and Error Types”">​</a></h2><h3 id="what-s-updated-2" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-2" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Added <code>session.error</code> event for invalid model selection; also added <code>ContextOverflowError</code>, and improved model variant availability check logic.</p><h3 id="what-s-the-use-for-you-2" tabindex="-1">What&#39;s the Use for You? <a class="header-anchor" href="#what-s-the-use-for-you-2" aria-label="Permalink to “What&#39;s the Use for You?”">​</a></h3><p>Troubleshooting model issues is no longer &quot;silent failure&quot; or vague errors. Logs and events will tell you faster what went wrong.</p><h3 id="how-to-use-2" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use-2" aria-label="Permalink to “How to Use?”">​</a></h3><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/01a-config-basics.html">Config Basics</a></p><p>👉 <strong>Extended Tutorial</strong>: <a href="/en/5-advanced/21-thinking-depth.html">Thinking Depth Configuration</a></p><p>👉 <strong>Official Docs</strong>: <a href="https://opencode.ai/docs/models" target="_blank" rel="noreferrer">Models</a></p><p><strong>Quick Experience</strong>:</p><ol><li>Deliberately fill in a non-existent model ID in config.</li><li>Start a session and observe event or log output.</li><li>Change back to an available model, verify session returns to normal.</li></ol><hr><h2 id="bug-fix-multiple-stability-fixes-for-desktop-tui-core" tabindex="-1">Bug Fix: Multiple Stability Fixes for Desktop / TUI / Core <a class="header-anchor" href="#bug-fix-multiple-stability-fixes-for-desktop-tui-core" aria-label="Permalink to “Bug Fix: Multiple Stability Fixes for Desktop / TUI / Core”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Including Homebrew upgrade occasionally requiring multiple runs, app terminal replay anomalies, unstable behavior after workspace reset, etc.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>These issues are centrally fixed in v1.1.54, with significantly improved stability for desktop, TUI, and core workflows.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>You&#39;re using ACP or IDE integration</td><td>✅ Recommend immediate upgrade</td></tr><tr><td>You frequently switch models/variants</td><td>✅ Recommend immediate upgrade</td></tr><tr><td>You mainly use desktop</td><td>✅ Recommend upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',49),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core-excerpt" tabindex="-1">Core (Excerpt) <a class="header-anchor" href="#core-excerpt" aria-label="Permalink to “Core (Excerpt)”">​</a></h3><ul><li>Publish session.error event for invalid model selection</li><li>Create file if it doesn&#39;t exist when writing via ACP</li><li>Add new ContextOverflowError type</li><li>Add skill discovery from URLs via well-known RFC</li><li>Parse mid-stream OpenAI response errors to prevent infinite retries</li><li>Resolve Homebrew upgrade requiring multiple runs</li></ul><h3 id="tui-excerpt" tabindex="-1">TUI (Excerpt) <a class="header-anchor" href="#tui-excerpt" aria-label="Permalink to “TUI (Excerpt)”">​</a></h3><ul><li>Use sender color for queued messages in TUI</li><li>Add --fork flag to duplicate sessions before continuing</li><li>Improve skills dialog readability</li></ul><h3 id="desktop-excerpt" tabindex="-1">Desktop (Excerpt) <a class="header-anchor" href="#desktop-excerpt" aria-label="Permalink to “Desktop (Excerpt)”">​</a></h3><ul><li>Fix terminal replay issues in app</li><li>Fix workspace reset and session navigation issues</li><li>Improve prompt input, sidebar, and file tree interactions</li><li>Add native Wayland toggle and more menu bar capabilities</li></ul><p>Official Release Notes:</p><ul><li><a href="https://github.com/anomalyco/opencode/releases/tag/v1.1.54" target="_blank" rel="noreferrer">https://github.com/anomalyco/opencode/releases/tag/v1.1.54</a></li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const m=t(l,[["render",s]]);